// variaveis de nós anteriores
const dados = $json;

const dataInicioStr = $('GetDates').item.json.initialDate.substring(0, 19);
const dataFimStr = $('GetDates').item.json.finalDate.substring(0, 19);

const dataInicio = new Date(dataInicioStr);
const dataFim = new Date(dataFimStr);

// periodo analisado com formato "diaInicio/mesInicio - diaFim/mesFim/anoFim"
const diaInicio = dataInicio.getDate().toString().padStart(2, '0');
const mesInicio = (dataInicio.getMonth() + 1).toString().padStart(2, '0');
const diaFim = dataFim.getDate().toString().padStart(2, '0');
const mesFim = (dataFim.getMonth() + 1).toString().padStart(2, '0');
const anoFim = dataFim.getFullYear().toString();

const periodoAnalisado = `${diaInicio}/${mesInicio} - ${diaFim}/${mesFim}/${anoFim}`;
const periodoShort = `${diaInicio}/${mesInicio}-${diaFim}/${mesFim}`;

function percentOfNumber(part, total) {
  return ((100 * part) / total);
}

function formatNumber(number, minPrecision = 1, maxPrecision = 2) {
  number = number ? number : 0;
  return {number, formatPtBr: number.toLocaleString('pt-br', {
      minimumFractionDigits: minPrecision,
      maximumFractionDigits: maxPrecision
    })
  };
}

function formatTime(seconds) {


    // Round to handle decimal inputs
    seconds = Math.round(Number(seconds));

    // Less than 60 seconds
    if (seconds < 60) {
        return seconds === 1 ? '1 second' : `${seconds}s`;
    }

    // Between 60 seconds and 1 hour (less than 3600 seconds)
    else if (seconds < 3600) {
        const minutes = Math.floor(seconds / 60);
        const remainingSeconds = seconds % 60;

        if (remainingSeconds === 0) {
            return minutes === 1 ? '1 minute' : `${minutes} minutes`;
        } else {
            const minuteStr = `${minutes}m`;
            const secondStr = `${remainingSeconds}s`;
            return `${minuteStr} ${secondStr}`;
        }
    }

    // 1 hour or more
    else {
        const hours = Math.floor(seconds / 3600);
        const remainingMinutes = Math.floor((seconds % 3600) / 60);

        let result = `${hours}h`;

        if (remainingMinutes > 0) {
            const minuteStr = `${remainingMinutes}m`;
            result += ` ${minuteStr}`;
        }

        return result;
    }
}

function percentOf(part, total, minPrecision = 1, maxPrecision = 2) {
  const number = percentOfNumber(Number(part), Number(total));
  return formatNumber(number, minPrecision, maxPrecision)
}

