function formatHourInterval(hour) {
  const startHour = hour.toString().padStart(2, '0');
  const nextHour = hour + 1;
  const endHour = nextHour.toString().padStart(2, '0');

  return `${startHour}:00-${endHour}:00`;
}

let frequencyHourTable = {};
for (let i = 0; i < 24; ++i) {
  frequencyHourTable[i] = {
    hourInterval: formatHourInterval(i),
    frequency: 0,
    percent: {number: 0, formatPtBr: "0,00"},
  }
}


for (let i = 0; i < sdrTimeInteractions.length; ++i) {
