  percentSdrMoreThanOneInteractionOfSdrActive,
  percentSdrThreeOrMoreInteractionOfSdrActive,
  percentSdrFiveOrMoreInteractionOfSdrActive,
  percentSdrTenOrMoreInteractionOfSdrActive,
  percentSdrAgentNotReplyLeadOfSdrActive,
  percentSdrAgentNotReplyFirstLeadOfSdrActive,
  percentSdrLeadNotReplyFirstAgentOfSdrActive,
  percentSdrAgentReplyLeadOfSdrActive,
  percentSdrAgentReplyLeadOnNewConversationOfSdrActive,
  percentQualifiedLeadsOfSdrEngagedLeads,
  percentQualifiedLeadsOfSdrActiveConversations,
  countResponseQualifiedFirstResponse,
  percentResponseFirstResponseOfQualifieds,
  convertions,
  percentConvertionOfQualifieds,
  frequencyHourTable,
  sortedFrequencies,
  frequencyWeekdayTable,
  sdrInboxTable,
  sdrLabelsQualificacao,
  sdrLabelsNavios,
  avgTimeToQualify,
  percentSalesNotEmptyNewConversationsnOfSalesActive,
  percentSalesEngagedOfActive,
  percentSalesAgentNotReplyFirstLeadOfSdrActive,
  percentSalesCountLastMessageWasLeadOfSdrActive,
  percentSalesLeadCountMissedFirstResponseOfActiveConversations,
  salesInboxTable,
  salesWithoutInterest,
  percentSalesWithoutInterestOfActive,
  ...formattedMessagesData
}

