// // variaveis de nós anteriores
const atualIndex = 5;
const anteriorIndex = 4;
const dadosPeriodoAtual = $("MessagesData").all()[atualIndex].json;
const dadosPeriodoAnterior = $("MessagesData").all()[anteriorIndex].json;

function compare(dataAtual, dataPrevious) {
  dataPrevious = Number(dataPrevious)
  dataAtual = Number(dataAtual)
  const difference = dataAtual - dataPrevious;
  let number = (100 * difference / dataPrevious);
  let formatPtBr = number.toLocaleString('pt-br', {
      minimumFractionDigits: 1,
      maximumFractionDigits: 2
  });
  return {number, formatPtBr}
} 

const comparativoSdrActiveConversations = 
  compare(dadosPeriodoAtual.sdr_active_conversations,
          dadosPeriodoAnterior.sdr_active_conversations)

const comparativoSalesActiveConversations = 
  compare(dadosPeriodoAtual.sales_active_conversations,
          dadosPeriodoAnterior.sales_active_conversations)

const comparativoSdrEngagedLeads = 
  compare(dadosPeriodoAtual.sdr_engaged_leads,
          dadosPeriodoAnterior.sdr_engaged_leads)

const comparativoSalesEngagedLeads = 
  compare(dadosPeriodoAtual.sales_engaged_leads,
          dadosPeriodoAnterior.sales_engaged_leads)

const comparativoCountQualifiedLeads = 
  compare(dadosPeriodoAtual.count_qualified_leads,
          dadosPeriodoAnterior.count_qualified_leads)

const percentQualifiedAtual = $('DataExtra').all()[atualIndex].json.percentQualifiedLeadsOfSdrEngagedLeads.number

const percentQualifiedAnterior = $('DataExtra').all()[anteriorIndex].json.percentQualifiedLeadsOfSdrEngagedLeads.number

const comparativoPercentQualifiedLeads = 
  compare(percentQualifiedAtual, percentQualifiedAnterior) 

const dataExtraAtual =  $('DataExtra').all()[atualIndex].json;
const dataExtraAnterior =  $('DataExtra').all()[anteriorIndex].json;

const percentQualifiedFirstResponseAtual =
  dataExtraAtual.percentResponseFirstResponseOfQualifieds.number

const percentQualifiedFirstResponseAnterior =
  dataExtraAnterior.percentResponseFirstResponseOfQualifieds.number

const comparativoQualifiedFirstResponse =
  compare(percentQualifiedFirstResponseAtual, 
          percentQualifiedFirstResponseAnterior)

const comparativoConvertions = (dataExtraAtual.convertions && dataExtraAnterior.convertions) 
  ? compare(dataExtraAtual.convertions, dataExtraAnterior.convertions)
  : null;

