function formatDate(date) {
    // Use Brazil/East or America/Sao_Paulo timezone
    const options = {
        timeZone: 'America/Sao_Paulo',
        year: 'numeric',
        month: '2-digit',
        day: '2-digit',
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
        hour12: false
    };

    const formatter = new Intl.DateTimeFormat('en-CA', options);
    const parts = formatter.formatToParts(date);

    const year = parts.find(p => p.type === 'year').value;
    const month = parts.find(p => p.type === 'month').value;
    const day = parts.find(p => p.type === 'day').value;
    const hour = parts.find(p => p.type === 'hour').value;
    const minute = parts.find(p => p.type === 'minute').value;
    const second = parts.find(p => p.type === 'second').value;
    const timezone = options.timeZone

    return `${year}-${month}-${day} ${hour}:${minute}:${second} ${timezone}`;
}

function calculateTimeWindow(dateEnd, windowDays = 7) {
    const windowEnd = dateEnd;

    const windowStart = new Date(dateEnd);
    windowStart.setDate(windowStart.getDate() - windowDays);
    windowStart.setSeconds(windowStart.getSeconds() + 1);

    // Create the output structure
    const result = {
      initialDate: formatDate(windowStart),
      finalDate: formatDate(windowEnd)
    }
    return result;
}

const now = Date.now() // timestamp in milliseconds
const monthEnd = new Date(now) // Convert to Date object

//const monthEnd = new Date('2026-03-16');

// Calculate different week ends correctly
const fourthWeekEnd = new Date(monthEnd) // Current date
const thirdWeekEnd = new Date(monthEnd)
thirdWeekEnd.setDate(monthEnd.getDate() - 7) // 7 days ago
const secondWeekEnd = new Date(monthEnd)
secondWeekEnd.setDate(monthEnd.getDate() - 14) // 14 days ago
const firstWeekEnd = new Date(monthEnd)
firstWeekEnd.setDate(monthEnd.getDate() - 21) // 21 days ago
const previousMonthEnd = new Date(monthEnd)
previousMonthEnd.setDate(monthEnd.getDate() - 28) // 28 days ago


return [ 
  calculateTimeWindow(firstWeekEnd, 7),
  calculateTimeWindow(secondWeekEnd, 7),
  calculateTimeWindow(thirdWeekEnd, 7),
  calculateTimeWindow(fourthWeekEnd, 7),
  calculateTimeWindow(previousMonthEnd, 28),
  calculateTimeWindow(monthEnd, 28),
];
